  2→import { randomUUID } from "node:crypto";
  3→import { readFileSync } from "node:fs";
  4→import { join } from "node:path";
  5→import { RecordId, Surreal } from "surrealdb";
  6→import {
  7→  getProjectGraphView,
  8→  getWorkspaceGraphOverview,
  9→  getFocusedGraphView,
 10→  type GraphEntityRecord,
 11→} from "../../../app/src/server/graph/queries";
 12→
 13→/**
 14→ * Acceptance tests for governance visualization in graph views.
 15→ *
 16→ * Covers:
 17→ * - AC-1.1..AC-1.4: Policy nodes with status filtering
 18→ * - AC-2.1..AC-2.4, AC-2.8: Intent nodes with status filtering + focused view
 19→ * - AC-4.1..AC-4.4: Governance edge classification
 20→ * - AC-X.4: Existing graph nodes continue to appear correctly
 21→ */
 22→
 23→const surrealUrl = process.env.SURREAL_URL ?? "ws://127.0.0.1:8000/rpc";
 24→const surrealUsername = process.env.SURREAL_USERNAME ?? "root";
 25→const surrealPassword = process.env.SURREAL_PASSWORD ?? "root";
 26→
 27→let surreal: Surreal;
 28→let namespace: string;
 29→let database: string;
 30→
 31→let workspaceRecord: RecordId<"workspace", string>;
 32→let projectRecord: RecordId<"project", string>;
 33→let taskRecord: RecordId<"task", string>;
 34→let identityRecord: RecordId<"identity", string>;
 35→
 36→// Policy records
 37→let activePolicyRecord: RecordId<"policy", string>;
 38→let testingPolicyRecord: RecordId<"policy", string>;
 39→let draftPolicyRecord: RecordId<"policy", string>;
 40→let deprecatedPolicyRecord: RecordId<"policy", string>;
 41→let supersededPolicyRecord: RecordId<"policy", string>;
 42→
 43→// Intent records
 44→let executingIntentRecord: RecordId<"intent", string>;
 45→let pendingVetoIntentRecord: RecordId<"intent", string>;
 46→let completedIntentRecord: RecordId<"intent", string>;
 47→let vetoedIntentRecord: RecordId<"intent", string>;
 48→let failedIntentRecord: RecordId<"intent", string>;
 49→
 50→// Agent session for gates edge
 51→let agentSessionRecord: RecordId<"agent_session", string>;
 52→
 53→beforeAll(async () => {
 54→  const runId = `${Date.now()}_${Math.floor(Math.random() * 100000)}`;
 55→  namespace = `smoke_gov_viz_${runId}`;
 56→  database = `gov_viz_${Math.floor(Math.random() * 100000)}`;
 57→
 58→  surreal = new Surreal();
 59→  await surreal.connect(surrealUrl);
 60→  await surreal.signin({ username: surrealUsername, password: surrealPassword });
 61→  await surreal.query(`DEFINE NAMESPACE ${namespace};`);
 62→  await surreal.use({ namespace });
 63→  await surreal.query(`DEFINE DATABASE ${database};`);
 64→  await surreal.use({ namespace, database });
 65→
 66→  const schemaSql = readFileSync(join(process.cwd(), "schema", "surreal-schema.surql"), "utf8");
 67→  await surreal.query(schemaSql);
 68→
 69→  const now = new Date();
 70→
 71→  // ── Workspace ──
 72→  workspaceRecord = new RecordId("workspace", randomUUID());
 73→  await surreal.create(workspaceRecord).content({
 74→    name: "Governance Viz Workspace",
 75→    status: "active",
 76→    onboarding_complete: true,
 77→    onboarding_turn_count: 0,
 78→    onboarding_summary_pending: false,
 79→    onboarding_started_at: now,
 80→    created_at: now,
 81→  });
 82→
 83→  // ── Identity ──
 84→  identityRecord = new RecordId("identity", randomUUID());
 85→  await surreal.query("CREATE $record CONTENT $content;", {
 86→    record: identityRecord,
 87→    content: { name: "Admin User", type: "human", workspace: workspaceRecord, created_at: now },
 88→  });
 89→  await surreal.query("RELATE $identity->member_of->$workspace SET added_at = $now;", {
 90→    identity: identityRecord,
 91→    workspace: workspaceRecord,
 92→    now,
 93→  });
 94→
 95→  // ── Project + Task ──
 96→  projectRecord = new RecordId("project", randomUUID());
 97→  await surreal.query("CREATE $record CONTENT $content;", {
 98→    record: projectRecord,
 99→    content: { name: "Gov Project", status: "active", workspace: workspaceRecord, created_at: now, updated_at: now },
100→  });
101→  await surreal.query("RELATE $workspace->has_project->$project SET added_at = $now;", {
102→    workspace: workspaceRecord,
103→    project: projectRecord,
104→    now,
105→  });
106→
107→  taskRecord = new RecordId("task", randomUUID());
108→  await surreal.query("CREATE $record CONTENT $content;", {
109→    record: taskRecord,
110→    content: { title: "Deploy staging", status: "open", workspace: workspaceRecord, created_at: now, updated_at: now },
111→  });
112→  await surreal.query("RELATE $task->belongs_to->$project SET added_at = $now;", {
113→    task: taskRecord,
114→    project: projectRecord,
115→    now,
116→  });
117→
118→  // ── Agent session (for gates edge) ──
119→  agentSessionRecord = new RecordId("agent_session", randomUUID());
120→  await surreal.query("CREATE $record CONTENT $content;", {
121→    record: agentSessionRecord,
122→    content: {
123→      status: "running",
124→      workspace: workspaceRecord,
125→      identity: identityRecord,
126→      created_at: now,
127→      updated_at: now,
128→    },
129→  });
130→
131→  // ── Policies (5 statuses) ──
132→  const policyBase = {
133→    version: 1,
134→    selector: {},
135→    rules: [{ id: "r1", condition: { field: "action", operator: "eq", value: "deploy" }, effect: "deny", priority: 100 }],
136→    human_veto_required: false,
137→    created_by: identityRecord,
138→    workspace: workspaceRecord,
139→    created_at: now,
140→  };
141→
142→  activePolicyRecord = new RecordId("policy", randomUUID());
143→  await surreal.query("CREATE $record CONTENT $content;", {
144→    record: activePolicyRecord,
145→    content: { ...policyBase, title: "Active Budget Guard", status: "active" },
146→  });
147→
148→  testingPolicyRecord = new RecordId("policy", randomUUID());
149→  await surreal.query("CREATE $record CONTENT $content;", {
150→    record: testingPolicyRecord,
151→    content: { ...policyBase, title: "Testing Rate Limiter", status: "testing" },
152→  });
153→
154→  draftPolicyRecord = new RecordId("policy", randomUUID());
155→  await surreal.query("CREATE $record CONTENT $content;", {
156→    record: draftPolicyRecord,
157→    content: { ...policyBase, title: "Draft Policy", status: "draft" },
158→  });
159→
160→  deprecatedPolicyRecord = new RecordId("policy", randomUUID());
161→  await surreal.query("CREATE $record CONTENT $content;", {
162→    record: deprecatedPolicyRecord,
163→    content: { ...policyBase, title: "Deprecated Policy", status: "deprecated" },
164→  });
165→
166→  supersededPolicyRecord = new RecordId("policy", randomUUID());
167→  await surreal.query("CREATE $record CONTENT $content;", {
168→    record: supersededPolicyRecord,
169→    content: { ...policyBase, title: "Superseded Policy", status: "superseded" },
170→  });
171→
172→  // ── Governance edges (only for active + testing) ──
173→  await surreal.query("RELATE $identity->governing->$policy SET created_at = $now;", {
174→    identity: identityRecord,
175→    policy: activePolicyRecord,
176→    now,
177→  });
178→  await surreal.query("RELATE $policy->protects->$workspace SET created_at = $now;", {
179→    policy: activePolicyRecord,
180→    workspace: workspaceRecord,
181→    now,
182→  });
183→  await surreal.query("RELATE $identity->governing->$policy SET created_at = $now;", {
184→    identity: identityRecord,
185→    policy: testingPolicyRecord,
186→    now,
187→  });
188→  await surreal.query("RELATE $policy->protects->$workspace SET created_at = $now;", {
189→    policy: testingPolicyRecord,
190→    workspace: workspaceRecord,
191→    now,
192→  });
193→
194→  // ── Intents (5 statuses) ──
195→  const intentBase = {
196→    reasoning: "test reasoning",
197→    priority: 50,
198→    action_spec: { provider: "test", action: "deploy", params: {} },
199→    requester: identityRecord,
200→    workspace: workspaceRecord,
201→    created_at: now,
202→  };
203→
204→  const traceRecord = new RecordId("trace", randomUUID());
205→  await surreal.query("CREATE $record CONTENT $content;", {
206→    record: traceRecord,
207→    content: { type: "intent_submission", actor: identityRecord, workspace: workspaceRecord, created_at: now },
208→  });
209→
210→  executingIntentRecord = new RecordId("intent", randomUUID());
211→  await surreal.query("CREATE $record CONTENT $content;", {
212→    record: executingIntentRecord,
213→    content: { ...intentBase, goal: "Deploy v2.1 to staging", status: "executing", trace_id: traceRecord },
214→  });
215→
216→  pendingVetoIntentRecord = new RecordId("intent", randomUUID());
217→  await surreal.query("CREATE $record CONTENT $content;", {
218→    record: pendingVetoIntentRecord,
219→    content: {
220→      ...intentBase,
221→      goal: "Scale database replicas",
222→      status: "pending_veto",
223→      trace_id: traceRecord,
224→      veto_expires_at: new Date(Date.now() + 5 * 60 * 1000),
225→    },
226→  });
227→
228→  completedIntentRecord = new RecordId("intent", randomUUID());
229→  await surreal.query("CREATE $record CONTENT $content;", {
230→    record: completedIntentRecord,
231→    content: { ...intentBase, goal: "Run test suite", status: "completed", trace_id: traceRecord },
232→  });
233→
234→  vetoedIntentRecord = new RecordId("intent", randomUUID());
235→  await surreal.query("CREATE $record CONTENT $content;", {
236→    record: vetoedIntentRecord,
237→    content: { ...intentBase, goal: "Drop production table", status: "vetoed", trace_id: traceRecord, veto_reason: "Too risky" },
238→  });
239→
240→  failedIntentRecord = new RecordId("intent", randomUUID());
241→  await surreal.query("CREATE $record CONTENT $content;", {
242→    record: failedIntentRecord,
243→    content: { ...intentBase, goal: "Broken deploy", status: "failed", trace_id: traceRecord, error_reason: "Timeout" },
244→  });
245→
246→  // ── Intent edges ──
247→  // triggered_by: executing intent -> task
248→  await surreal.query("RELATE $intent->triggered_by->$task SET created_at = $now;", {
249→    intent: executingIntentRecord,
250→    task: taskRecord,
251→    now,
252→  });
253→  // gates: executing intent -> agent session
254→  await surreal.query("RELATE $intent->gates->$session SET created_at = $now;", {
255→    intent: executingIntentRecord,
256→    session: agentSessionRecord,
257→    now,
258→  });
259→}, 30_000);
260→
261→afterAll(async () => {
262→  if (!surreal) return;
263→  try {
264→    await surreal.query(`REMOVE DATABASE ${database};`);
265→    await surreal.query(`REMOVE NAMESPACE ${namespace};`);
266→  } catch {}
267→  await surreal.close().catch(() => {});
268→}, 10_000);
269→
270→// ─────────────────────────────────────────────────────────────────────────────
271→// AC-1: Policy nodes in graph view
272→// ─────────────────────────────────────────────────────────────────────────────
273→
274→describe("AC-1: Policy status filtering in workspace graph", () => {
275→  it("AC-1.1: active and testing policies appear as nodes", async () => {
276→    const graph = await getWorkspaceGraphOverview({ surreal, workspaceRecord });
277→
278→    const policyNodes = graph.entities.filter((e) => e.kind === "policy");
279→    const names = policyNodes.map((n) => n.name);
280→
281→    expect(names).toContain("Active Budget Guard");
282→    expect(names).toContain("Testing Rate Limiter");
283→  });
284→
285→  it("AC-1.2: governing edges connect identity to policy", async () => {
286→    const graph = await getWorkspaceGraphOverview({ surreal, workspaceRecord });
287→
288→    const governingEdges = graph.edges.filter((e) => e.kind === "governing");
289→    expect(governingEdges.length).toBeGreaterThanOrEqual(2);
290→  });
291→
292→  it("AC-1.3: protects edges connect policy to workspace", async () => {
293→    const graph = await getWorkspaceGraphOverview({ surreal, workspaceRecord });
294→
295→    const protectsEdges = graph.edges.filter((e) => e.kind === "protects");
296→    expect(protectsEdges.length).toBeGreaterThanOrEqual(2);
297→  });
298→
299→  it("AC-1.4: draft, deprecated, and superseded policies are excluded", async () => {
300→    const graph = await getWorkspaceGraphOverview({ surreal, workspaceRecord });
301→
302→    const policyNames = graph.entities
303→      .filter((e) => e.kind === "policy")
304→      .map((e) => e.name);
305→
306→    expect(policyNames).not.toContain("Draft Policy");
307→    expect(policyNames).not.toContain("Deprecated Policy");
308→    expect(policyNames).not.toContain("Superseded Policy");
309→  });
310→});
311→
312→// ─────────────────────────────────────────────────────────────────────────────
313→// AC-2: Intent nodes in graph view
314→// ─────────────────────────────────────────────────────────────────────────────
315→
316→describe("AC-2: Intent status filtering in workspace graph", () => {
317→  it("AC-2.1: non-terminal intents appear as nodes", async () => {
318→    const graph = await getWorkspaceGraphOverview({ surreal, workspaceRecord });
319→
320→    const intentNodes = graph.entities.filter((e) => e.kind === "intent");
321→    const names = intentNodes.map((n) => n.name);
322→
323→    expect(names).toContain("Deploy v2.1 to staging");
324→    expect(names).toContain("Scale database replicas");
325→  });
326→
327→  it("AC-2.2: triggered_by edges connect intent to task", async () => {
328→    const graph = await getWorkspaceGraphOverview({ surreal, workspaceRecord });
329→
330→    const triggeredByEdges = graph.edges.filter((e) => e.kind === "triggered_by");
331→    expect(triggeredByEdges.length).toBeGreaterThanOrEqual(1);
332→  });
333→
334→  it("AC-2.3: gates edges connect intent to agent session", async () => {
335→    const graph = await getWorkspaceGraphOverview({ surreal, workspaceRecord });
336→
337→    const gatesEdges = graph.edges.filter((e) => e.kind === "gates");
338→    expect(gatesEdges.length).toBeGreaterThanOrEqual(1);
339→  });
340→
341→  it("AC-2.4: completed, vetoed, and failed intents are excluded", async () => {
342→    const graph = await getWorkspaceGraphOverview({ surreal, workspaceRecord });
343→
344→    const intentNames = graph.entities
345→      .filter((e) => e.kind === "intent")
346→      .map((e) => e.name);
347→
348→    expect(intentNames).not.toContain("Run test suite");
349→    expect(intentNames).not.toContain("Drop production table");
350→    expect(intentNames).not.toContain("Broken deploy");
351→  });
352→
353→  it("AC-2.8: focused view accepts intent as center entity", async () => {
354→    const graph = await getFocusedGraphView({
355→      surreal,
356→      workspaceRecord,
357→      centerEntityRecord: executingIntentRecord as GraphEntityRecord,
358→      depth: 1,
359→    });
360→
361→    // Center entity should be present
362→    const centerEntity = graph.entities.find((e) => e.name === "Deploy v2.1 to staging");
363→    expect(centerEntity).toBeDefined();
364→    expect(centerEntity!.kind).toBe("intent");
365→
366→    // Should reach task via triggered_by
367→    const taskEntity = graph.entities.find((e) => e.kind === "task");
368→    expect(taskEntity).toBeDefined();
369→
370→    // Should reach agent session via gates
371→    const sessionEntity = graph.entities.find((e) => e.kind === "agent_session");
372→    expect(sessionEntity).toBeDefined();
373→  });
374→});
375→
376→// ─────────────────────────────────────────────────────────────────────────────
377→// AC-2 + AC-1: Focused view for policy
378→// ─────────────────────────────────────────────────────────────────────────────
379→
380→describe("Focused view centering on policy", () => {
381→  it("focused view accepts policy as center entity", async () => {
382→    const graph = await getFocusedGraphView({
383→      surreal,
384→      workspaceRecord,
385→      centerEntityRecord: activePolicyRecord as GraphEntityRecord,
386→      depth: 1,
387→    });
388→
389→    // Center entity should be present
390→    const centerEntity = graph.entities.find((e) => e.name === "Active Budget Guard");
391→    expect(centerEntity).toBeDefined();
392→    expect(centerEntity!.kind).toBe("policy");
393→
394→    // Should reach identity via governing
395→    const identityEntity = graph.entities.find((e) => e.kind === "identity");
396→    expect(identityEntity).toBeDefined();
397→
398→    // Should reach workspace via protects
399→    const workspaceEntity = graph.entities.find((e) => e.kind === "workspace");
400→    expect(workspaceEntity).toBeDefined();
401→  });
402→});
403→
404→// ─────────────────────────────────────────────────────────────────────────────
405→// AC-4: Edge style classification
406→// ─────────────────────────────────────────────────────────────────────────────
407→
408→describe("AC-4: Governance edges are classified distinctly", () => {
409→  it("AC-4.1/4.2: governing and protects edges appear in graph", async () => {
410→    const graph = await getWorkspaceGraphOverview({ surreal, workspaceRecord });
411→
412→    const edgeKinds = graph.edges.map((e) => e.kind);
413→    expect(edgeKinds).toContain("governing");
414→    expect(edgeKinds).toContain("protects");
415→  });
416→
417→  it("AC-4.3/4.4: triggered_by and gates edges appear in graph", async () => {
418→    const graph = await getWorkspaceGraphOverview({ surreal, workspaceRecord });
419→
420→    const edgeKinds = graph.edges.map((e) => e.kind);
421→    expect(edgeKinds).toContain("triggered_by");
422→    expect(edgeKinds).toContain("gates");
423→  });
424→
425→  it("governance edges coexist with structural edges", async () => {
426→    const graph = await getWorkspaceGraphOverview({ surreal, workspaceRecord });
427→
428→    const edgeKinds = new Set(graph.edges.map((e) => e.kind));
429→    // Structural edges still present
430→    expect(edgeKinds.has("belongs_to")).toBe(true);
431→    // Governance edges also present
432→    expect(edgeKinds.has("governing")).toBe(true);
433→    expect(edgeKinds.has("protects")).toBe(true);
434→  });
435→});
436→
437→// ─────────────────────────────────────────────────────────────────────────────
438→// AC-X.4: Existing entities still visible
439→// ─────────────────────────────────────────────────────────────────────────────
440→
441→describe("AC-X.4: Existing graph nodes unaffected by governance additions", () => {
442→  it("project, task, and identity still appear in workspace graph", async () => {
443→    const graph = await getWorkspaceGraphOverview({ surreal, workspaceRecord });
444→
445→    const kinds = graph.entities.map((e) => e.kind);
446→    expect(kinds).toContain("project");
447→    expect(kinds).toContain("task");
448→    expect(kinds).toContain("identity");
449→  });
450→
451→  it("project graph view still includes task and structural edges", async () => {
452→    const graph = await getProjectGraphView({
453→      surreal,
454→      workspaceRecord,
455→      projectRecord,
456→    });
457→
458→    const entityKinds = graph.entities.map((e) => e.kind);
459→    expect(entityKinds).toContain("task");
460→
461→    const edgeKinds = graph.edges.map((e) => e.kind);
462→    expect(edgeKinds).toContain("belongs_to");
463→  });
464→});
