26→    case "decision": return "var(--entity-decision-muted)";
27→    case "question": return "var(--entity-question-muted)";
28→    case "observation": return "var(--entity-decision-muted)";
29→    case "suggestion": return "var(--entity-question-muted)";
30→    case "person": return "var(--entity-person-muted)";
31→    case "workspace": return "var(--entity-project-muted)";
32→    case "message": return "var(--entity-task-muted)";
