39→export type EdgeStyleResult = {
40→  stroke: string;
41→  strokeDasharray: string;
42→  opacity: number;
43→};
44→
45→export function edgeStyle(type: string): EdgeStyleResult {
46→  switch (type) {
47→    case "depends_on":
48→      return { stroke: "#5a5a64", strokeDasharray: "4 2", opacity: 0.8 };
49→    case "conflicts_with":
50→      return { stroke: "#d66a8a", strokeDasharray: "none", opacity: 0.9 };
51→    case "belongs_to":
52→    case "has_feature":
53→    case "has_task":
54→    case "has_project":
55→      return { stroke: "#5b8dee", strokeDasharray: "none", opacity: 0.3 };
56→    default:
57→      return { stroke: "#5b8dee", strokeDasharray: "none", opacity: 0.5 };
58→  }
59→}
