142→function toRecordIdString(record: RecordId<string, string>): string {
143→  return record.id as string;
144→}
145→
146→function toIsoString(value: string | Date): string {
147→  return value instanceof Date ? value.toISOString() : new Date(value).toISOString();
148→}
149→
150→function normalizeSearchValue(value: string): string {
151→  return value
152→    .trim()
153→    .toLowerCase()
154→    .replace(/[^a-z0-9\s]/g, " ")
155→    .replace(/\s+/g, " ");
156→}
