158→export function parseRecordIdString<T extends string>(
159→  value: string,
160→  allowedTables: T[],
161→  fallbackTable?: T,
162→): RecordId<T, string> {
163→  const normalized = value.trim();
164→  if (normalized.length === 0) {
165→    throw new Error("record id is required");
166→  }
167→
168→  const separatorIndex = normalized.indexOf(":");
169→  if (separatorIndex === -1) {
170→    if (!fallbackTable) {
171→      throw new Error(`record id must be prefixed with one of: ${allowedTables.join(", ")}`);
172→    }
173→
174→    return new RecordId(fallbackTable, normalized) as RecordId<T, string>;
175→  }
176→
177→  const table = normalized.slice(0, separatorIndex) as T;
178→  const id = normalized.slice(separatorIndex + 1);
179→  if (!allowedTables.includes(table)) {
180→    throw new Error(`record id table must be one of: ${allowedTables.join(", ")}`);
181→  }
182→
183→  if (id.length === 0) {
184→    throw new Error("record id is missing its identifier component");
185→  }
186→
187→  return new RecordId(table, id) as RecordId<T, string>;
188→}
