250→  if (table === "workspace") {
251→    return toRecordIdString(entityRecord) === toRecordIdString(workspaceRecord);
252→  }
253→
254→  if (table === "project") {
255→    const [rows] = await surreal
256→      .query<[Array<{ id: RecordId<"has_project", string> }>]>(
257→        "SELECT id FROM has_project WHERE `in` = $workspace AND out = $project LIMIT 1;",
258→        { workspace: workspaceRecord, project: entityRecord },
259→      )
260→      .collect<[Array<{ id: RecordId<"has_project", string> }>]>();
261→
262→    return rows.length > 0;
