265→  if (table === "person") {
266→    const [rows] = await surreal
267→      .query<[Array<{ id: RecordId<"member_of", string> }>]>(
268→        "SELECT id FROM member_of WHERE `in` = $person AND out = $workspace LIMIT 1;",
269→        { workspace: workspaceRecord, person: entityRecord },
270→      )
271→      .collect<[Array<{ id: RecordId<"member_of", string> }>]>();
272→
273→    return rows.length > 0;
274→  }
275→
276→  if (table === "identity") {
277→    const [rows] = await surreal
278→      .query<[Array<{ id: RecordId<"identity", string> }>]>(
