1607→  const [rows] = await surreal
1608→    .query<[UnifiedEdgeRow[]]>(
1609→      "RETURN fn::edges_between($entityIds);",
1610→      { entityIds },
1611→    )
1612→    .collect<[UnifiedEdgeRow[]]>();
1613→
1614→  return rows.map((row) => ({
1615→    id: toRecordIdString(row.id),
1616→    fromId: toRecordIdString(row.in),
1617→    toId: toRecordIdString(row.out),
1618→    kind: row.kind ?? row.id.table.name,
1619→    confidence: row.confidence ?? 1.0,
1620→  }));
