1668→export async function getFocusedGraphView(input: {
1669→  surreal: Surreal;
1670→  workspaceRecord: RecordId<"workspace", string>;
1671→  centerEntityRecord: GraphEntityRecord;
1672→  depth: number;
1673→}): Promise<GraphViewRawResult> {
1674→  const clampedDepth = Math.max(1, Math.min(3, input.depth));
1675→
1676→  const scoped = await isEntityInWorkspace(input.surreal, input.workspaceRecord, input.centerEntityRecord);
1677→  if (!scoped) {
1678→    throw new Error("entity is outside the current workspace scope");
1679→  }
1680→
1681→  const collected = new Map<string, GraphEntityRecord>();
1682→  collected.set(toRecordIdString(input.centerEntityRecord), input.centerEntityRecord);
1683→
1684→  let frontier: RecordId<string, string>[] = [input.centerEntityRecord];
1685→
1686→  for (let hop = 0; hop < clampedDepth; hop++) {
1687→    if (frontier.length === 0) {
1688→      break;
1689→    }
1690→
1691→    const nextFrontier: RecordId<string, string>[] = [];
1692→
1693→    const [rows] = await input.surreal
1694→      .query<[Array<{ in: RecordId<string, string>; out: RecordId<string, string> }>]>(
1695→        "RETURN fn::graph_neighbors($currentIds);",
1696→        { currentIds: frontier },
1697→      )
1698→      .collect<[Array<{ in: RecordId<string, string>; out: RecordId<string, string> }>]>();
1699→
1700→    for (const row of rows) {
1701→      for (const endpoint of [row.in, row.out]) {
1702→        const key = toRecordIdString(endpoint);
1703→        if (collected.has(key)) continue;
1704→
1705→        const inScope = await isEntityInWorkspace(input.surreal, input.workspaceRecord, endpoint as GraphEntityRecord);
1706→        if (!inScope) continue;
1707→
1708→        collected.set(key, endpoint as GraphEntityRecord);
1709→        nextFrontier.push(endpoint);
1710→      }
1711→    }
1712→
1713→    frontier = nextFrontier;
1714→  }
1715→
1716→  const allRecords = Array.from(collected.values());
1717→  const entities = await resolveEntityNames(input.surreal, allRecords);
1718→  const edges = await collectEntityRelationEdges(input.surreal, allRecords);
1719→
1720→  return { entities, edges };
1721→}
