 899→export async function listEntityNeighbors(input: {
 900→  surreal: Surreal;
 901→  workspaceRecord: RecordId<"workspace", string>;
 902→  entityRecord: GraphEntityRecord;
 903→  limit: number;
 904→}): Promise<EntityNeighbor[]> {
 905→  const [rows] = await input.surreal
 906→    .query<[UnifiedEdgeRow[]]>(
 907→      "RETURN fn::entity_edges($entity, $limit);",
 908→      { entity: input.entityRecord, limit: input.limit },
 909→    )
 910→    .collect<[UnifiedEdgeRow[]]>();
 911→
 912→  const neighbors: EntityNeighbor[] = [];
 913→  const seen = new Set<string>();
 914→
 915→  for (const row of rows) {
 916→    const edgeTable = row.id.table.name;
 917→    const relationKind = row.kind ?? edgeTable;
 918→    const direction = toRecordIdString(row.in) === toRecordIdString(input.entityRecord) ? "outgoing" : "incoming";
 919→    const neighborRecord = direction === "outgoing" ? row.out : row.in;
 920→    const key = `${relationKind}:${toRecordIdString(neighborRecord)}`;
 921→    if (seen.has(key)) continue;
 922→
 923→    const scoped = await isEntityInWorkspace(input.surreal, input.workspaceRecord, neighborRecord as GraphEntityRecord);
 924→    if (!scoped) continue;
 925→
 926→    const name = await readEntityName(input.surreal, neighborRecord as GraphEntityRecord);
 927→    if (!name) continue;
 928→
 929→    seen.add(key);
 930→    neighbors.push({
 931→      id: toRecordIdString(neighborRecord),
 932→      kind: neighborRecord.table.name as GraphEntityTable,
 933→      name,
 934→      relationKind,
 935→      direction,
 936→      confidence: row.confidence ?? 1.0,
 937→    });
 938→  }
 939→
 940→  return neighbors;
 941→}
