 943→/** Maps entity tables to their identity-referencing owner field */
 944→const IDENTITY_OWNER_FIELDS: Partial<Record<GraphEntityTable, string>> = {
 945→  task: "owner",
 946→  decision: "decided_by",
 947→  feature: "owner",
 948→};
 949→
 950→async function resolveEntityAttribution(
 951→  surreal: Surreal,
 952→  entityRecord: GraphEntityRecord,
 953→  table: GraphEntityTable,
 954→): Promise<IdentityAttribution | undefined> {
 955→  const ownerField = IDENTITY_OWNER_FIELDS[table];
 956→  if (!ownerField) return undefined;
 957→
 958→  // Step 1: get actor identity from owner field
 959→  const [actorRows] = await surreal
 960→    .query<[Array<{ actor_name: string; actor_type: string; owner_id: RecordId }>]>(
 961→      `SELECT ${ownerField}.name AS actor_name, ${ownerField}.type AS actor_type, ${ownerField} AS owner_id FROM $record;`,
 962→      { record: entityRecord },
 963→    )
 964→    .collect<[Array<{ actor_name: string; actor_type: string; owner_id: RecordId }>]>();
 965→
 966→  if (actorRows.length === 0 || !actorRows[0].actor_name) return undefined;
 967→
 968→  const { actor_name, actor_type, owner_id } = actorRows[0];
 969→  const actorType = actor_type as "human" | "agent" | "system";
 970→
 971→  if (actorType === "human" || actorType === "system") {
 972→    return { actorName: actor_name, actorType };
 973→  }
 974→
 975→  // Step 2: for agent identities, resolve managed_by chain
 976→  const [managedByRows] = await surreal
 977→    .query<[Array<{ managed_by_name: Array<string> }>]>(
 978→      `SELECT ->identity_agent->agent.managed_by.name AS managed_by_name FROM $identity;`,
 979→      { identity: owner_id },
 980→    )
 981→    .collect<[Array<{ managed_by_name: Array<string> }>]>();
 982→
 983→  const accountableHumanName = managedByRows[0]?.managed_by_name?.[0];
 984→
 985→  return {
 986→    actorName: actor_name,
 987→    actorType,
 988→    ...(accountableHumanName ? { accountableHumanName } : {}),
 989→  };
 990→}
