822→-- Graph traversal functions: query edges across all relation tables from SurrealQL.
823→
824→DEFINE FUNCTION fn::entity_edges($entity: record, $lim: int) {
825→  RETURN SELECT id, `in`, out, kind, confidence
826→    FROM entity_relation, belongs_to, has_feature, has_task, has_project,
827→         depends_on, owns, observes, suggests_for, subtask_of
828→    WHERE `in` = $entity OR out = $entity
829→    LIMIT $lim;
830→};
831→
832→DEFINE FUNCTION fn::edges_between($ids: array) {
833→  RETURN SELECT id, `in`, out, kind, confidence
834→    FROM entity_relation, belongs_to, has_feature, has_task, has_project,
835→         depends_on, owns, observes, suggests_for, subtask_of
836→    WHERE `in` IN $ids AND out IN $ids;
837→};
838→
839→DEFINE FUNCTION fn::graph_neighbors($ids: array) {
840→  RETURN SELECT `in`, out
841→    FROM entity_relation, belongs_to, has_feature, has_task, has_project,
842→         depends_on, owns, observes, suggests_for, subtask_of
843→    WHERE `in` IN $ids OR out IN $ids;
844→};
845→
846→DEFINE FUNCTION fn::workspace_entity_ids($ws: record<workspace>) {
847→  LET $projects = (SELECT VALUE out FROM has_project WHERE `in` = $ws);
848→  LET $features = (SELECT VALUE out FROM has_feature WHERE `in` IN $projects);
849→  LET $tasks = (SELECT VALUE out FROM has_task WHERE `in` IN $features);
850→  LET $belongs_project = (SELECT VALUE `in` FROM belongs_to WHERE out IN $projects);
851→  LET $belongs_feature = (SELECT VALUE `in` FROM belongs_to WHERE out IN $features);
852→  LET $identities = (SELECT VALUE `in` FROM member_of WHERE out = $ws);
853→  LET $provenance = (
854→    SELECT VALUE out FROM extraction_relation
855→    WHERE `in` IN (
856→      SELECT VALUE id FROM message
857→      WHERE conversation IN (
858→        SELECT VALUE id FROM conversation WHERE workspace = $ws
859→      )
860→    )
861→  );
862→  RETURN array::distinct(
863→    $projects + $features + $tasks +
864→    $belongs_project + $belongs_feature +
865→    $identities + $provenance
866→  );
867→};
868→
869→DEFINE FUNCTION fn::project_entity_ids($ws: record<workspace>, $project: record<project>) {
870→  LET $features = (SELECT VALUE out FROM has_feature WHERE `in` = $project);
871→  LET $tasks = (SELECT VALUE out FROM has_task WHERE `in` IN $features);
872→  LET $belongs_project = (SELECT VALUE `in` FROM belongs_to WHERE out = $project);
873→  LET $belongs_feature = (SELECT VALUE `in` FROM belongs_to WHERE out IN $features);
874→  LET $identities = (SELECT VALUE `in` FROM member_of WHERE out = $ws);
875→  LET $provenance = (
876→    SELECT VALUE out FROM extraction_relation
877→    WHERE `in` IN (
878→      SELECT VALUE id FROM message
879→      WHERE conversation IN (
880→        SELECT VALUE id FROM conversation WHERE workspace = $ws
881→      )
882→    )
883→  );
884→  RETURN array::distinct(
885→    [$project] + $features + $tasks +
886→    $belongs_project + $belongs_feature +
887→    $identities + $provenance
888→  );
889→};
