19→    case "intent": return "#14b8a6";
20→  }
21→}
22→
23→function titleCase(s: string): string {
24→  return s.split(" ").map((w) => w.charAt(0).toUpperCase() + w.slice(1)).join(" ");
25→}
26→
27→export function transformToReagraph(raw: GraphViewRawResult): GraphResponse {
28→  const connectionCounts = new Map<string, number>();
29→  for (const edge of raw.edges) {
30→    connectionCounts.set(edge.fromId, (connectionCounts.get(edge.fromId) ?? 0) + 1);
31→    connectionCounts.set(edge.toId, (connectionCounts.get(edge.toId) ?? 0) + 1);
32→  }
33→
34→  const nodes: ReagraphNode[] = raw.entities.map((entity) => {
35→    const kind = entity.kind as EntityKind;
36→    const kindBoost = kind === "project" ? 20
37→      : kind === "feature" ? 10
38→      : kind === "person" ? 8
39→      : 0;
40→    return {
41→      id: entity.id,
42→      label: entity.name.length > 32 ? entity.name.slice(0, 32) + "\u2026" : entity.name,
43→      fill: entityColor(kind),
44→      data: {
45→        kind,
46→        connectionCount: (connectionCounts.get(entity.id) ?? 0) + kindBoost,
47→        status: undefined,
48→      },
49→    };
50→  });
51→
52→  const edges: ReagraphEdge[] = raw.edges.map((edge) => ({
53→    id: edge.id,
54→    source: edge.fromId,
55→    target: edge.toId,
56→    label: titleCase(edge.kind.replace(/_/g, " ")),
57→    data: {
58→      type: edge.kind,
59→      confidence: edge.confidence,
60→    },
61→  }));
62→
63→  return { nodes, edges };
64→}
