 24→async function getWorkspaceProjectRows(
 25→  surreal: Surreal,
 26→  workspaceRecord: RecordId<"workspace", string>,
 27→): Promise<ProjectRow[]> {
 28→  const [rows] = await surreal
 29→    .query<[ProjectRow[]]>(
 30→      "SELECT id, name FROM project WHERE id IN (SELECT VALUE out FROM has_project WHERE `in` = $workspace);",
 31→      { workspace: workspaceRecord },
 32→    )
 33→    .collect<[ProjectRow[]]>();
 34→
 35→  return rows;
 36→}
