 47→async function loadProjectContext(
 48→  surreal: Surreal,
 49→  workspaceRecord: RecordId<"workspace", string>,
 50→): Promise<ProjectContext> {
 51→  const projects = await getWorkspaceProjectRows(surreal, workspaceRecord);
 52→  return {
 53→    projectRecords: projects.map((p) => p.id),
 54→    projectNameById: new Map(projects.map((p) => [toRecordIdString(p.id), p.name])),
 55→  };
 56→}
