181→        "FROM conflicts_with",
182→        "WHERE `in` IN (SELECT VALUE id FROM decision WHERE workspace = $workspace)",
183→        "OR `in` IN (SELECT VALUE id FROM feature WHERE workspace = $workspace)",
184→        "OR out IN (SELECT VALUE id FROM decision WHERE workspace = $workspace)",
185→        "OR out IN (SELECT VALUE id FROM feature WHERE workspace = $workspace)",
186→        "ORDER BY detected_at DESC",
187→        "LIMIT $limit;",
