649→export type RecentExtractionRow = {
650→  edgeId: string;
651→  sourceKind: "message" | "document_chunk" | "git_commit";
652→  sourceId: string;
653→  entityId: string;
654→  entityKind: string;
655→  entityName: string;
656→  confidence: number;
657→  extractedAt: string;
