794→  const entityId = `agent_session:${rawId}`;
795→  const entityName = row.task_title ?? `Agent session ${rawId}`;
796→
797→  const isError = row.orchestrator_status === "error";
798→  const tier = isError ? "blocking" : "review";
799→
800→  const reason = isError
801→    ? `Agent error${row.error_message ? `: ${row.error_message}` : ""}`
802→    : `Agent completed work on '${entityName}' -- review ready`;
803→
804→  const actions: GovernanceFeedAction[] = isError
805→    ? [{ action: "discuss", label: "Discuss" }, { action: "abort", label: "Abort" }]
806→    : [{ action: "review", label: "Review" }, { action: "abort", label: "Abort" }];
807→
808→  return {
809→    id: `${entityId}:${row.orchestrator_status}`,
810→    tier,
811→    entityId,
812→    entityKind: "agent_session",
813→    entityName,
814→    reason,
815→    status: row.orchestrator_status,
816→    createdAt: row.started_at instanceof Date ? row.started_at.toISOString() : new Date(row.started_at).toISOString(),
817→    actions,
818→  };
819→}
