910→async function readEntityNameByTable(
911→  surreal: Surreal,
912→  record: RecordId<string, string>,
913→  table: string,
914→): Promise<string | undefined> {
915→  if (table === "workspace" || table === "project" || table === "person" || table === "feature") {
916→    const row = await surreal.select<{ name: string }>(record);
917→    return row?.name;
918→  }
919→
920→  if (table === "task") {
921→    const row = await surreal.select<{ title: string }>(record);
922→    return row?.title;
923→  }
924→
925→  if (table === "decision") {
926→    const row = await surreal.select<{ summary: string }>(record);
927→    return row?.summary;
928→  }
929→
930→  if (table === "question") {
931→    const row = await surreal.select<{ text: string }>(record);
932→    return row?.text;
933→  }
934→
935→  return undefined;
936→}
