190→// ─────────────────────────────────────────────────────────────────────────────
191→// Query helper: simulates the feed query for recently vetoed intents
192→// ─────────────────────────────────────────────────────────────────────────────
193→
194→type VetoedIntentRow = {
195→  id: RecordId<"intent", string>;
196→  goal: string;
197→  status: string;
198→  veto_reason?: string;
199→  evaluation?: {
200→    decision: string;
201→    risk_score: number;
202→    reason: string;
203→  };
204→  updated_at: Date | string;
205→};
206→
207→async function listRecentlyVetoedIntents(
208→  db: Surreal,
209→  wsRecord: RecordId<"workspace", string>,
210→  cutoffHours = 24,
211→): Promise<VetoedIntentRow[]> {
212→  const cutoff = new Date(Date.now() - cutoffHours * 60 * 60 * 1000);
213→  const rows = (await db.query(
214→    `SELECT id, goal, status, veto_reason, evaluation, updated_at
215→     FROM intent
216→     WHERE workspace = $ws
217→       AND status = 'vetoed'
218→       AND updated_at > $cutoff
219→     ORDER BY updated_at DESC;`,
220→    { ws: wsRecord, cutoff },
221→  )) as Array<VetoedIntentRow[]>;
222→  return rows[0] ?? [];
223→}
224→
225→async function listPendingVetoIntentIds(
226→  db: Surreal,
227→  wsRecord: RecordId<"workspace", string>,
228→): Promise<Set<string>> {
229→  const rows = (await db.query(
230→    `SELECT VALUE id FROM intent
231→     WHERE workspace = $ws AND status = 'pending_veto';`,
232→    { ws: wsRecord },
233→  )) as Array<Array<RecordId<"intent", string>>>;
234→  return new Set((rows[0] ?? []).map((r) => `intent:${r.id as string}`));
235→}
236→
237→type AwarenessFeedItem = {
238→  entityId: string;
239→  entityKind: string;
240→  entityName: string;
241→  reason: string;
242→  status: string;
243→  actions: Array<{ action: string; label: string }>;
244→};
245→
246→function mapVetoedIntentToFeedItem(row: VetoedIntentRow): AwarenessFeedItem {
247→  const evalReason = row.evaluation?.reason ?? "";
248→  return {
249→    entityId: `intent:${row.id.id as string}`,
250→    entityKind: "intent",
251→    entityName: row.goal,
252→    reason: `Vetoed: ${evalReason}`,
253→    status: "vetoed",
254→    actions: [{ action: "discuss", label: "Discuss" }],
255→  };
256→}
257→
258→function buildAwarenessTier(
259→  vetoedRows: VetoedIntentRow[],
260→  blockingEntityIds: Set<string>,
261→): AwarenessFeedItem[] {
262→  const items: AwarenessFeedItem[] = [];
263→  for (const row of vetoedRows) {
264→    const entityId = `intent:${row.id.id as string}`;
265→    // Dedup: skip if already in blocking tier
266→    if (blockingEntityIds.has(entityId)) continue;
267→    items.push(mapVetoedIntentToFeedItem(row));
268→  }
269→  return items;
270→}
271→
272→// ─────────────────────────────────────────────────────────────────────────────
273→// AC-3: Vetoed intents in feed awareness tier
274→// ─────────────────────────────────────────────────────────────────────────────
275→
276→describe("AC-3.1: 24h window filtering", () => {
277→  it("vetoed intents within 24h are returned by query", async () => {
278→    const rows = await listRecentlyVetoedIntents(surreal, workspaceRecord);
279→    const goals = rows.map((r) => r.goal);
280→
281→    expect(goals).toContain("Purge cache");
282→    expect(goals).toContain("Delete staging env");
283→  });
284→
285→  it("AC-3.6: vetoed intents older than 24h are excluded", async () => {
286→    const rows = await listRecentlyVetoedIntents(surreal, workspaceRecord);
287→    const goals = rows.map((r) => r.goal);
288→
289→    expect(goals).not.toContain("Drop production table");
290→  });
291→});
292→
293→describe("AC-3.2..AC-3.5: Feed item shape", () => {
294→  it("AC-3.2: entityKind is intent and entityName is goal", async () => {
295→    const rows = await listRecentlyVetoedIntents(surreal, workspaceRecord);
296→    const item = mapVetoedIntentToFeedItem(rows.find((r) => r.goal === "Purge cache")!);
297→
298→    expect(item.entityKind).toBe("intent");
299→    expect(item.entityName).toBe("Purge cache");
300→  });
301→
302→  it("AC-3.3: reason includes Vetoed and evaluation reason", async () => {
303→    const rows = await listRecentlyVetoedIntents(surreal, workspaceRecord);
304→    const item = mapVetoedIntentToFeedItem(rows.find((r) => r.goal === "Purge cache")!);
305→
306→    expect(item.reason).toContain("Vetoed");
307→    expect(item.reason).toContain("risk exceeded budget threshold");
308→  });
309→
310→  it("AC-3.4: status is vetoed", async () => {
311→    const rows = await listRecentlyVetoedIntents(surreal, workspaceRecord);
312→    const item = mapVetoedIntentToFeedItem(rows[0]!);
313→
314→    expect(item.status).toBe("vetoed");
315→  });
316→
317→  it("AC-3.5: only Discuss action offered", async () => {
318→    const rows = await listRecentlyVetoedIntents(surreal, workspaceRecord);
319→    const item = mapVetoedIntentToFeedItem(rows[0]!);
320→
321→    expect(item.actions).toHaveLength(1);
322→    expect(item.actions[0].action).toBe("discuss");
323→    expect(item.actions[0].label).toBe("Discuss");
324→  });
325→});
326→
327→describe("AC-3.7: Recency sort", () => {
328→  it("multiple vetoed intents sorted by most recent first", async () => {
329→    const rows = await listRecentlyVetoedIntents(surreal, workspaceRecord);
330→
331→    // "Purge cache" (2h ago) should come before "Delete staging env" (8h ago)
332→    const goals = rows.map((r) => r.goal);
333→    const purgeIdx = goals.indexOf("Purge cache");
334→    const deleteIdx = goals.indexOf("Delete staging env");
335→
336→    expect(purgeIdx).toBeLessThan(deleteIdx);
337→  });
338→});
339→
340→describe("AC-3.8: Dedup with blocking tier", () => {
341→  it("pending_veto intent is excluded from awareness tier", async () => {
342→    const vetoedRows = await listRecentlyVetoedIntents(surreal, workspaceRecord);
343→    const blockingIds = await listPendingVetoIntentIds(surreal, workspaceRecord);
344→
345→    // Verify the pending_veto intent is in the blocking set
346→    const pendingId = `intent:${pendingVetoIntentRecord.id as string}`;
347→    expect(blockingIds.has(pendingId)).toBe(true);
348→
349→    // Build awareness tier with dedup
350→    const awareness = buildAwarenessTier(vetoedRows, blockingIds);
351→    const awarenessEntityIds = awareness.map((i) => i.entityId);
352→
353→    // pending_veto intent should NOT appear in awareness
354→    expect(awarenessEntityIds).not.toContain(pendingId);
355→
356→    // vetoed intents should still appear
357→    expect(awareness.length).toBeGreaterThanOrEqual(2);
358→  });
359→
360→  it("vetoed intents not in blocking tier are preserved in awareness", async () => {
361→    const vetoedRows = await listRecentlyVetoedIntents(surreal, workspaceRecord);
362→    const blockingIds = await listPendingVetoIntentIds(surreal, workspaceRecord);
363→
364→    const awareness = buildAwarenessTier(vetoedRows, blockingIds);
365→    const names = awareness.map((i) => i.entityName);
