41→export type EdgeStyleResult = {
42→  stroke: string;
43→  strokeDasharray: string;
44→  opacity: number;
45→};
46→
47→export function edgeStyle(type: string): EdgeStyleResult {
48→  switch (type) {
49→    case "depends_on":
50→      return { stroke: "#5a5a64", strokeDasharray: "4 2", opacity: 0.8 };
51→    case "conflicts_with":
52→      return { stroke: "#d66a8a", strokeDasharray: "none", opacity: 0.9 };
53→    case "belongs_to":
54→    case "has_feature":
55→    case "has_task":
56→    case "has_project":
57→      return { stroke: "#5b8dee", strokeDasharray: "none", opacity: 0.3 };
58→    case "governing":
59→    case "protects":
60→    case "triggered_by":
61→    case "gates":
62→    case "vetoed_by":
63→      return { stroke: "#f59e0b", strokeDasharray: "6 3", opacity: 0.7 };
64→    default:
65→      return { stroke: "#5b8dee", strokeDasharray: "none", opacity: 0.5 };
66→  }
67→}
