 3→
 4→type Relationship = EntityDetailResponse["relationships"][number];
 5→
 6→type GroupedRelationships = Map<string, Relationship[]>;
 7→
 8→function groupByRelationKind(relationships: Relationship[]): GroupedRelationships {
 9→  const groups = new Map<string, Relationship[]>();
10→  for (const rel of relationships) {
11→    const key = `${rel.relationKind}:${rel.direction}`;
12→    const group = groups.get(key);
13→    if (group) {
14→      group.push(rel);
15→    } else {
16→      groups.set(key, [rel]);
17→    }
18→  }
19→  return groups;
20→}
21→
22→function formatGroupLabel(kind: string, direction: "incoming" | "outgoing"): string {
23→  const label = kind.replace(/_/g, " ");
24→  return direction === "outgoing" ? label : `${label} (incoming)`;
25→}
26→
27→export function RelationshipList({
28→  relationships,
29→  onEntityClick,
30→}: {
31→  relationships: Relationship[];
32→  onEntityClick: (entityId: string) => void;
33→}) {
34→  const groups = groupByRelationKind(relationships);
35→
36→  if (groups.size === 0) {
37→    return <p className="entity-detail-meta">No relationships found.</p>;
38→  }
39→
40→  return (
41→    <div className="entity-detail-section">
42→      <h4>Relationships</h4>
43→      {Array.from(groups.entries()).map(([key, items]) => {
44→        const direction = items[0].direction;
45→        const kind = items[0].relationKind;
46→        return (
47→          <div key={key} className="relationship-group">
48→            <span className="relationship-group-label">{formatGroupLabel(kind, direction)}</span>
49→            {items.map((item) => (
50→              <button
51→                key={item.id}
52→                type="button"
53→                className="relationship-item"
54→                onClick={() => onEntityClick(`${item.kind}:${item.id}`)}
55→              >
56→                <EntityBadge kind={item.kind} />
57→                {item.name}
58→              </button>
59→            ))}
60→          </div>
61→        );
62→      })}
63→    </div>
64→  );
65→}
