 4→// Resolved hex values for OKLCH entity colors — Three.js/WebGL cannot parse CSS variables.
 5→export function entityColor(kind: EntityKind): string {
 6→  switch (kind) {
 7→    case "project": return "#3b82f6";   // oklch(0.65 0.15 250)
 8→    case "feature": return "#14b8a6";   // oklch(0.65 0.15 170)
 9→    case "task": return "#22c55e";      // oklch(0.70 0.15 145)
10→    case "decision": return "#eab308";  // oklch(0.70 0.15 55)
11→    case "question": return "#a855f7";  // oklch(0.65 0.15 300)
12→    case "observation": return "#ef4444";
13→    case "suggestion": return "#06b6d4"; // cyan-500
14→    case "person": return "#f97316";    // oklch(0.65 0.15 25)
15→    case "workspace": return "#3b82f6";
16→    case "message": return "#22c55e";
17→    case "identity": return "#f97316";
18→    case "agent_session": return "#22c55e";
19→    case "intent": return "#14b8a6";
20→    case "policy": return "#f59e0b";   // amber-500 — governance gold
21→  }
22→}
23→
24→function titleCase(s: string): string {
25→  return s.split(" ").map((w) => w.charAt(0).toUpperCase() + w.slice(1)).join(" ");
26→}
27→
28→export function transformToReagraph(raw: GraphViewRawResult): GraphResponse {
29→  const connectionCounts = new Map<string, number>();
30→  for (const edge of raw.edges) {
31→    connectionCounts.set(edge.fromId, (connectionCounts.get(edge.fromId) ?? 0) + 1);
32→    connectionCounts.set(edge.toId, (connectionCounts.get(edge.toId) ?? 0) + 1);
33→  }
34→
35→  const nodes: ReagraphNode[] = raw.entities.map((entity) => {
36→    const kind = entity.kind as EntityKind;
37→    const kindBoost = kind === "project" ? 20
38→      : kind === "feature" ? 10
39→      : kind === "person" ? 8
40→      : 0;
41→    return {
42→      id: entity.id,
43→      label: entity.name.length > 32 ? entity.name.slice(0, 32) + "\u2026" : entity.name,
44→      fill: entityColor(kind),
45→      data: {
46→        kind,
47→        connectionCount: (connectionCounts.get(entity.id) ?? 0) + kindBoost,
48→        status: undefined,
49→      },
50→    };
51→  });
52→
53→  const edges: ReagraphEdge[] = raw.edges.map((edge) => ({
54→    id: edge.id,
55→    source: edge.fromId,
56→    target: edge.toId,
57→    label: titleCase(edge.kind.replace(/_/g, " ")),
58→    data: {
59→      type: edge.kind,
60→      confidence: edge.confidence,
61→    },
62→  }));
63→
64→  return { nodes, edges };
65→}
